export function cloneMaze(key: MazeKey): number[][] {
  return MAZES[key].map(r => [...r]);
}

export function countDots(map: number[][]): number {
  let count = 0;
  for (let r = 0; r < map.length; r++) {
    for (let c = 0; c < map[r].length; c++) {
      if (map[r][c] === 2) count++;
    }
  }
  return count;
}

export interface MazeMeta {
  gateRow: number;
  gateCol: number;
  penExit: { row: number; col: number };
  ghostStarts: { row: number; col: number }[];
  playerStart: { row: number; col: number };
  penCenter: { row: number; col: number };
}

export function analyzeMaze(map: number[][]): MazeMeta {
  let gateRow = -1, gateCol = -1;
  for (let r = 0; r < map.length && gateRow < 0; r++) {
    for (let c = 0; c < map[r].length; c++) {
      if (map[r][c] === 4) { gateRow = r; gateCol = c; break; }
    }
  }
  if (gateRow < 0) { gateRow = 8; gateCol = 9; }
  let playerRow = map.length - 2;
  for (let r = map.length - 2; r > gateRow + 3; r--) {
    if (map[r][gateCol] !== 1) { playerRow = r; break; }
  }
  return {
    gateRow, gateCol,
    penExit: { row: gateRow - 1, col: gateCol },
    ghostStarts: [
      { row: gateRow + 1, col: gateCol },
      { row: gateRow + 1, col: gateCol - 1 },
      { row: gateRow + 1, col: gateCol + 1 },
    ],
    playerStart: { row: playerRow, col: gateCol },
    penCenter: { row: gateRow + 1, col: gateCol },
  };
}
